mapper.update:
UPDATE daily_activity
SET motion_score = #{motionScore}
WHERE resident_id = #{residentId}
AND date = #{date}

mapper.select:
SELECT id, resident_id, date, motion_score
FROM daily_activity
WHERE resident_id = #{residentId}
AND date = #{date}

SELECT id, resident_id, date, motion_score
FROM daily_activity
WHERE resident_id = #{residentId}
AND date BETWEEN #{start} AND #{end}
ORDER BY date ASC
